+        "camera",
+        "clip",
+        "--node",
+        "ios-node",
+        "--duration",
+        "3000",
+        "--no-audio",
+      ],
+      { from: "user" },
+    );
+
+    expect(callGateway).toHaveBeenNthCalledWith(
+      2,
+      expect.objectContaining({
+        method: "node.invoke",
+        params: expect.objectContaining({
